## Scope
Write comprehensive unit tests for the new atomic rate limiter implementation.

## Test Cases

### 1. Basic Functionality
```typescript
describe("RateLimiter.tryConsume", () => {
  it("should allow request when under limit", () => {
    const limiter = new RateLimiter();
    const result = limiter.tryConsume("key", { limit: 10, windowMs: 1000 });
    expect(result.allowed).toBe(true);
    expect(result.info.remaining).toBe(9);
  });

  it("should deny request when at limit", () => {
    const limiter = new RateLimiter();
    for (let i = 0; i < 10; i++) {
      limiter.tryConsume("key", { limit: 10, windowMs: 1000 });
    }
    const result = limiter.tryConsume("key", { limit: 10, windowMs: 1000 });
    expect(result.allowed).toBe(false);
    expect(result.info.remaining).toBe(0);
  });
});
```

### 2. Window Reset
```typescript
it("should reset counter after window expires", async () => {
  const limiter = new RateLimiter();
  limiter.tryConsume("key", { limit: 1, windowMs: 100 });

  let result = limiter.tryConsume("key", { limit: 1, windowMs: 100 });
  expect(result.allowed).toBe(false);

  await sleep(150);

  result = limiter.tryConsume("key", { limit: 1, windowMs: 100 });
  expect(result.allowed).toBe(true);
});
```

### 3. Multiple Keys
```typescript
it("should track different keys independently", () => {
  const limiter = new RateLimiter();

  limiter.tryConsume("key1", { limit: 1, windowMs: 1000 });
  const result1 = limiter.tryConsume("key1", { limit: 1, windowMs: 1000 });
  const result2 = limiter.tryConsume("key2", { limit: 1, windowMs: 1000 });

  expect(result1.allowed).toBe(false);
  expect(result2.allowed).toBe(true);
});
```

### 4. Concurrency Simulation
```typescript
it("should handle concurrent requests correctly", async () => {
  const limiter = new RateLimiter();
  const config = { limit: 10, windowMs: 10000 };

  // Simulate 100 concurrent requests
  const results = await Promise.all(
    Array.from({ length: 100 }, () => 
      Promise.resolve(limiter.tryConsume("key", config))
    )
  );

  const allowed = results.filter(r => r.allowed).length;
  const denied = results.filter(r => !r.allowed).length;

  expect(allowed).toBe(10);
  expect(denied).toBe(90);
});
```

### 5. Rate Limit Headers
```typescript
it("should return correct rate limit info", () => {
  const limiter = new RateLimiter();
  const config = { limit: 10, windowMs: 1000 };

  const result = limiter.tryConsume("key", config);

  expect(result.info.limit).toBe(10);
  expect(result.info.remaining).toBe(9);
  expect(result.info.resetAt).toBeInstanceOf(Date);
});
```

