  setError(e instanceof Error ? e : new Error("Unknown error"));

  if (process.env.NODE_ENV === "development" || mockMode) {
    // Only in dev: fall back to mock
    setData(mockData);
    setUsingMockData(true);
  } else {
    // Production: show error, no mock data
    setData(null);
  }
}

// Return the mock data flag so UI can indicate it
